-- Script d'initialisation de la base de données Supabase pour le Portfolio --

-- 1. Table des Projets
CREATE TABLE projects (
  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, 
  title TEXT NOT NULL, 
  category TEXT NOT NULL, 
  image TEXT NOT NULL, 
  techs TEXT[] NOT NULL, 
  description TEXT NOT NULL, 
  details TEXT NOT NULL, 
  github TEXT, 
  demo TEXT, 
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()) );

-- 2. Table des Expériences 
CREATE TABLE experiences ( 
  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, 
  role TEXT NOT NULL, 
  company TEXT NOT NULL, 
  period TEXT NOT NULL, 
  description TEXT[] NOT NULL, 
  details TEXT NOT NULL, 
  technologies TEXT[] NOT NULL, 
  achievements TEXT[] NOT NULL, 
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()) );

-- 3. Table des Services 
CREATE TABLE services ( 
  id TEXT PRIMARY KEY, 
  title TEXT NOT NULL, 
  description TEXT NOT NULL, 
  long_description TEXT NOT NULL, 
  icon_name TEXT NOT NULL, 
  color TEXT NOT NULL, 
  features TEXT[] NOT NULL, 
  advantages TEXT[] NOT NULL, 
  use_cases TEXT[] NOT NULL, 
  technologies TEXT[] NOT NULL, 
  duration TEXT NOT NULL, 
  deliverables TEXT[] NOT NULL, 
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()) );

-- 4. Table des Compétences (Skills) 
CREATE TABLE skills ( 
  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, 
  category TEXT NOT NULL, 
  name TEXT NOT NULL, 
  level INTEGER NOT NULL, 
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()) );

-- 5. Table des Témoignages 
CREATE TABLE testimonials ( 
  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, 
  name TEXT NOT NULL, 
  role TEXT NOT NULL, 
  message TEXT NOT NULL, 
  avatar TEXT NOT NULL, 
  is_active BOOLEAN DEFAULT false,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()) );

-- Autoriser la lecture publique 
ALTER TABLE projects ENABLE ROW LEVEL SECURITY; 
ALTER TABLE experiences ENABLE ROW LEVEL SECURITY; 
ALTER TABLE services ENABLE ROW LEVEL SECURITY; 
ALTER TABLE skills ENABLE ROW LEVEL SECURITY; 
ALTER TABLE testimonials ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Allow public read access on projects" ON projects FOR SELECT USING (true); 
CREATE POLICY "Allow public read access on experiences" ON experiences FOR SELECT USING (true); 
CREATE POLICY "Allow public read access on services" ON services FOR SELECT USING (true); 
CREATE POLICY "Allow public read access on skills" ON skills FOR SELECT USING (true); 
CREATE POLICY "Allow public read access on testimonials" ON testimonials FOR SELECT USING (is_active = true);
CREATE POLICY "Allow public insert on testimonials" ON testimonials FOR INSERT WITH CHECK (true);
CREATE POLICY "Allow admin all access on testimonials" ON testimonials FOR ALL TO authenticated USING (true) WITH CHECK (true);

