INSERT INTO projects (title, category, image, techs, description, details, github, demo) VALUES ('Dashboard Analytique E-commerce', 'Autres', 'https://picsum.photos/seed/dashboard/800/600', ARRAY['React', 'Python', 'FastAPI', 'Pandas'], 'Une plateforme interactive pour visualiser les ventes et prédire les tendances futures grâce au Machine Learning.', 'Ce projet combine un frontend React moderne avec un backend FastAPI performant. Le modèle de Machine Learning entraîné avec Scikit-learn prédit les ventes avec une précision de 85%.', '#', 'sit.f'), ('Application de Gestion de Tâches', 'Dev', 'https://picsum.photos/seed/taskapp/800/600', ARRAY['React', 'Node.js', 'MongoDB', 'Tailwind'], 'Application full-stack de gestion de tâches avec authentification et temps réel.', 'Développement complet d''une application SaaS permettant la collaboration en temps réel via WebSockets.', '#', '#'), ('Classification d''Images Médicales', 'Data', 'https://picsum.photos/seed/medical/800/600', ARRAY['TensorFlow', 'Python', 'OpenCV'], 'Modèle de Deep Learning pour la détection précoce de maladies sur des radiographies.', 'Utilisation de réseaux de neurones convolutifs (CNN) pour atteindre une précision de 92% sur un dataset de 10 000 images.', '#', '#'), ('Portfolio Interactif', 'Dev', 'https://picsum.photos/seed/portfolio/800/600', ARRAY['React', 'Framer Motion', 'Tailwind'], 'Mon portfolio personnel présentant mes compétences et projets.', 'Création d''une interface utilisateur fluide avec des animations avancées et un support complet du mode sombre.', '#', '#'), ('Analyseur de Sentiments NLP', 'Data', 'https://picsum.photos/seed/nlp/800/600', ARRAY['Python', 'Hugging Face', 'PyTorch', 'Streamlit'], 'Application web analysant le sentiment des avis clients en temps réel.', 'Utilisation d''un modèle transformer pré-entraîné (BERT) fine-tuné sur un corpus d''avis en français, déployé via une interface Streamlit interactive.', '#', '#'), ('Plateforme de E-learning', 'Dev', 'https://picsum.photos/seed/elearning/800/600', ARRAY['Next.js', 'TypeScript', 'Prisma', 'Stripe'], 'Plateforme complète de cours en ligne avec paiements intégrés.', 'Architecture moderne avec Next.js App Router, base de données PostgreSQL gérée avec Prisma, et intégration de Stripe pour les abonnements.', '#', '#');

-- Expériences 
INSERT INTO experiences (role, company, period, description, details, technologies, achievements) VALUES ('Data Scientist Senior', 'Tech Innovators Inc.', '2021 - Présent', ARRAY['Développement de modèles prédictifs augmentant le CA de 15%.', 'Mise en place de pipelines de données automatisés avec Apache Airflow.', 'Mentorat de développeurs juniors.'], 'Chez Tech Innovators Inc., je dirige l''implémentation d''algorithmes d''apprentissage automatique pour optimiser les ventes de commerce électronique à grande échelle. Mes tâches quotidiennes englobent la conception de réseaux neuronaux complexes, l''optimisation de requêtes Big Data et la supervision d''une équipe de Data Analysts.', ARRAY['Python', 'Pandas', 'Scikit-learn', 'TensorFlow', 'Apache Airflow', 'Docker', 'AWS'], ARRAY['Conception d''un modèle de recommandation personnalisé en temps réel ayant généré +15% de CA en 6 mois.', 'Migration complète de pipelines de données legacy vers Apache Airflow, réduisant les temps de traitement quotidiens de 35%.', 'Mise en place d''un framework interne d''évaluation de modèles ML (A/B testing automatisé).']), ('Développeur Full-Stack', 'WebSolutions Agency', '2018 - 2021', ARRAY['Création d''applications web sur mesure pour divers clients.', 'Migration d''une architecture monolithique vers des microservices.', 'Optimisation des performances front-end (temps de chargement réduit de 40%).'], 'En tant que Développeur Full-Stack principal chez WebSolutions, j''ai collaboré étroitement avec des chefs de produit pour concevoir et déployer plus de 15 applications web hautement performantes. J''ai mené la transition vers les frameworks SPA modernes (React et TypeScript) et renforcé l''intégration continue.', ARRAY['React', 'TypeScript', 'Node.js', 'Express', 'PostgreSQL', 'Tailwind CSS', 'Git'], ARRAY['Refonte de l''interface client majeure d''un grand compte logistique, améliorant le score d''utilisabilité UX de 50%.', 'Monétisation réussie d''une plateforme de e-learning intégrant le processeur de paiement Stripe.', 'Mise en place d''un système robuste d''authentification par jeton (JWT) avec session sécurisée.']), ('Formation : Master en Data Science', 'Université des Sciences', '2016 - 2018', ARRAY['Spécialisation en Machine Learning et Big Data.', 'Projet de fin d''études sur le traitement du langage naturel (NLP).'], 'Ce Master m''a permis d''acquérir des bases théoriques solides et des compétences pratiques poussées en statistiques multivariées, calcul intensif et programmation scientifique.', ARRAY['R', 'Python', 'SQL', 'Hadoop', 'Spark', 'Matplotlib'], ARRAY['Mémoire de recherche de fin d''études axé sur le Fine-Tuning de modèles de langage (NLP / BERT) appliqué aux avis francophones.', 'Validation de projets académiques concrets en utilisant l''écosystème Hadoop/Spark pour l''analyse de pétaoctets de logs web.']);

-- Services 
INSERT INTO services (id, title, description, long_description, icon_name, color, features, advantages, use_cases, technologies, duration, deliverables) VALUES ('analytics', 'Analyse & Science des Données', 'Transformation de vos données brutes en insights stratégiques et décisions éclairées.', 'La science des données est au cœur de la transformation digitale. Je vous aide à extraire la valeur cachée dans vos données pour prendre des décisions basées sur des faits plutôt que sur l''intuition.', 'chart', 'bg-orange-100 text-orange-600 dark:bg-orange-950/40 dark:text-orange-400', ARRAY['Exploration et nettoyage de données', 'Analyses exploratrices avancées', 'Visualisations interactives et tableaux de bord', 'Rapports d''analyse approfondis'], ARRAY['Identification de tendances et patterns cachés', 'Optimisation des processus métier', 'Augmentation de la rentabilité et des revenus', 'Réduction des risques opérationnels'], ARRAY['Analyse comportementale des clients', 'Segmentation et prédiction de churn', 'Analyse de rentabilité produit/service', 'Détection d''anomalies et fraudes', 'Études de marché et tendances'], ARRAY['Python', 'Pandas', 'NumPy', 'Matplotlib', 'Seaborn', 'Jupyter', 'SQL'], '2-4 semaines', ARRAY['Rapport d''analyse complet', 'Visualisations professionnelles', 'Recommandations actionnables', 'Présentation exécutive']), ('ml', 'Machine Learning & IA', 'Développement de modèles prédictifs et solutions IA pour automatiser vos processus métier.', 'Automatisez vos flux de décision complexes en intégrant de l''intelligence artificielle à vos applications. Je conçois des modèles robustes, précis et scalables adaptés à votre contexte.', 'brain', 'bg-purple-100 text-purple-600 dark:bg-purple-950/40 dark:text-purple-400', ARRAY['Développement de modèles ML sur mesure', 'Prédictions et classification', 'Optimisation d''algorithmes', 'Déploiement et monitoring'], ARRAY['Automatisation des tâches répétitives', 'Amélioration continue grâce à l''apprentissage', 'Précision accrue des prédictions de vente', 'Personnalisation de l''expérience utilisateur'], ARRAY['Recommandations personnalisées', 'Prédiction des ventes et de la demande', 'Classification automatique d''images', 'Chatbots internes (RAG)', 'Maintenance préventive industrielle'], ARRAY['Python', 'Scikit-Learn', 'TensorFlow', 'PyTorch', 'Hugging Face', 'MLflow'], '4-8 semaines', ARRAY['Code source documenté', 'API de prédiction / Modèle entraîné', 'Script de réapprentissage automatique', 'Rapport de performance & métriques ML']), ('data-engineering', 'Data Engineering', 'Construction d''architectures de données robustes et scalables pour propulser vos opérations.', 'Pour faire de la science des données, il faut d''abord une base solide. Je conçois des entrepôts de données et des pipelines ETL/ELT fluides pour fiabiliser et automatiser vos flux d''information.', 'database', 'bg-emerald-100 text-emerald-600 dark:bg-emerald-950/40 dark:text-emerald-400', ARRAY['Conception de pipelines ETL/ELT', 'Architecture bases de données', 'Automatisation des traitements', 'Optimisation des performances'], ARRAY['Données fiables, propres et centralisées', 'Réduction des temps de latence des requêtes', 'Évolutivité de l''infrastructure de données', 'Sécurisation et conformité des flux de données'], ARRAY['Entrepôts de données (Data Warehouse)', 'Pipelines de données en temps réel', 'Migration vers le Cloud', 'Automatisation de rapports', 'Gestion de lacs de données (Data Lake)'], ARRAY['Python', 'SQL', 'Apache Spark', 'Airflow', 'PostgreSQL', 'Docker', 'AWS/GCP'], '3-6 semaines', ARRAY['Infrastructure as Code (IaC)', 'Code complet des pipelines de données', 'Documentation de l''architecture', 'Configateurs de monitoring & alertes']);

