-- ============================================================================== 
-- MIGRATION SUPABASE - PARTIE 3 : TABLES RESTANTES (Interactions & Admin) -- ==============================================================================

-- 1. Table des Certifications 
CREATE TABLE certifications ( 
  id TEXT PRIMARY KEY, 
  title TEXT NOT NULL, 
  issuer TEXT NOT NULL, 
  date TEXT NOT NULL, 
  credential_id TEXT, 
  category TEXT NOT NULL DEFAULT 'dev', 
  skills TEXT[] NOT NULL DEFAULT '{}', 
  description TEXT, 
  verify_url TEXT, 
  logo_color TEXT DEFAULT 'from-blue-600 via-blue-400 to-indigo-500', 
  status TEXT DEFAULT 'published', 
  attachment_url TEXT, 
  attachment_type TEXT, 
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()) 
);

-- 2. Table des Messages de Contact 
CREATE TABLE contact_messages ( 
  id TEXT PRIMARY KEY, 
  name TEXT NOT NULL, 
  email TEXT NOT NULL, 
  subject TEXT NOT NULL, 
  message TEXT NOT NULL, 
  read BOOLEAN DEFAULT FALSE, 
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()) 
);

-- 3. Table des Messages Flottants (Love Messages / Notifications Hero) 
--CREATE TABLE floating_messages ( id TEXT PRIMARY KEY, sender TEXT NOT NULL, text TEXT NOT NULL, emoji TEXT, bubble_color TEXT NOT NULL, x_pos NUMERIC NOT NULL DEFAULT 50, y_pos NUMERIC NOT NULL DEFAULT 50, scale NUMERIC NOT NULL DEFAULT 1.0, speed NUMERIC NOT NULL DEFAULT 20, created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()) );

-- 4. Table des Abonnés Newsletter 
CREATE TABLE newsletter_subscribers (
  email TEXT PRIMARY KEY, 
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()) 
);

-- 5. Table des Statistiques de Visites 
CREATE TABLE visits_stats ( 
  id TEXT PRIMARY KEY, 
  ip TEXT, 
  user_agent TEXT, 
  path TEXT, 
  country TEXT, 
  city TEXT, 
  device TEXT, 
  browser TEXT, 
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()) 
);

-- 6. Table des CV Générés 
CREATE TABLE generated_resumes ( 
  id TEXT PRIMARY KEY, 
  full_name TEXT NOT NULL, 
  job_title TEXT NOT NULL, 
  company_name TEXT, 
  job_description TEXT, 
  generated_content JSONB NOT NULL, 
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()) 
);

-- 7. Table de Configuration Admin Access 
CREATE TABLE admin_access ( id INTEGER PRIMARY KEY DEFAULT 1, 
  password_hash TEXT NOT NULL, 
  voice_bypass_enabled BOOLEAN DEFAULT FALSE, 
  failed_attempts INTEGER DEFAULT 0, 
  locked_until TIMESTAMP WITH TIME ZONE, 
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()), 
  CONSTRAINT admin_access_single_row CHECK (id = 1) 
);

