-- 1. Table de Configuration GitHub 
CREATE TABLE github_config ( 
  id INTEGER PRIMARY KEY DEFAULT 1, 
  username TEXT DEFAULT 'delsDin', 
  token TEXT, 
  sync_enabled BOOLEAN DEFAULT true, 
  excluded_repos TEXT[] DEFAULT '{}', 
  organizations TEXT[] DEFAULT '{}', 
  collaborators TEXT[] DEFAULT '{}', 
  only_contributed_collab BOOLEAN DEFAULT true, 
  repos_cache JSONB DEFAULT '[]'::jsonb, 
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()), 
  CONSTRAINT github_config_single_row CHECK (id = 1) 
);

-- 2. Table de Configuration CV par Défaut 
CREATE TABLE cv_config ( 
  id INTEGER PRIMARY KEY DEFAULT 1, 
  full_name TEXT DEFAULT '', 
  job_title TEXT DEFAULT '', 
  avatar_url TEXT DEFAULT '', 
  summary TEXT DEFAULT '', 
  email TEXT DEFAULT '', 
  phone TEXT DEFAULT '', 
  location TEXT DEFAULT '', 
  github TEXT DEFAULT '', 
  linkedin TEXT DEFAULT '', 
  website TEXT DEFAULT '', 
  show_website BOOLEAN DEFAULT true, 
  languages JSONB DEFAULT '[]'::jsonb, 
  template TEXT DEFAULT 'split', 
  font_family TEXT DEFAULT 'sans', 
  color_theme TEXT DEFAULT 'midnight', 
  paper_bg TEXT DEFAULT 'white', 
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()), 
  CONSTRAINT cv_config_single_row CHECK (id = 1) 
);

-- 3. Table de Configuration Audio / Assistant Vocal 
CREATE TABLE voice_config ( 
  id INTEGER PRIMARY KEY DEFAULT 1, 
  bg_trigger_enabled BOOLEAN DEFAULT false, 
  trigger_keywords TEXT DEFAULT 'dels, bonjour dels', 
  stop_keywords TEXT DEFAULT 'c''est bon, arrête, attend, stop', 
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()), 
  CONSTRAINT voice_config_single_row CHECK (id = 1) 
);

