-- ==========================================

CREATE TABLE IF NOT EXISTS public.maintenance_config (
  id INTEGER PRIMARY KEY DEFAULT 1,
  is_active BOOLEAN DEFAULT false,
  start_date TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()),
  reason TEXT,
  auto_reopen BOOLEAN DEFAULT false,
  auto_reopen_date TIMESTAMP WITH TIME ZONE,
  reopen_date TEXT,
  reopened_at TIMESTAMP WITH TIME ZONE,
  CONSTRAINT maintenance_config_single_row CHECK (id = 1)
);

ALTER TABLE public.maintenance_config ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Allow public read access on maintenance_config" ON public.maintenance_config FOR SELECT USING (true);
CREATE POLICY "Allow admin all access on maintenance_config" ON public.maintenance_config FOR ALL TO authenticated USING (true) WITH CHECK (true);

INSERT INTO public.maintenance_config (id, is_active, reason, auto_reopen)
VALUES (1, false, 'Maintenance technique en cours.', false)
ON CONFLICT (id) DO NOTHING;

-- ==========================================
-- JOURNALISATION DES INCIDENTS (LOGS D'ERREURS)
-- ==========================================

CREATE TABLE IF NOT EXISTS public.incident_logs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  source TEXT NOT NULL,
  error_message TEXT NOT NULL,
  error_stack TEXT,
  severity TEXT NOT NULL DEFAULT 'warning', -- 'info', 'warning', 'critical'
  metadata JSONB DEFAULT '{}'::jsonb,
  settled BOOLEAN NOT NULL DEFAULT false,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW())
);

-- Ensure settled column exists in case database is already created
ALTER TABLE public.incident_logs ADD COLUMN IF NOT EXISTS settled BOOLEAN NOT NULL DEFAULT false;

ALTER TABLE public.incident_logs ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Allow public insert on incident_logs" ON public.incident_logs FOR INSERT WITH CHECK (true);
CREATE POLICY "Allow admin all access on incident_logs" ON public.incident_logs FOR ALL TO authenticated USING (true) WITH CHECK (true);